// ─── /utilityreport ────────────────────────────────────────────────────────

export async function handleUtilityReport(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const userId = ctx.from?.id;
  if (!userId) return;

  try {
    const stats = await getHitStats(7);
    const shardInfos = listTopicShards(userId);

    const active: string[] = [];
    const silentFacts: string[] = [];
    const silentWiki: string[] = [];

    for (const s of shardInfos) {
      const count = stats.get(`fact:${s.topic}`) ?? 0;
      if (count >= 3) active.push(`fact:${s.topic} (${count})`);
      else if (count === 0) silentFacts.push(s.topic);
    }
    for (const [k, v] of stats) {
      if (k.startsWith("wiki:") && v >= 3) active.push(`${k} (${v})`);
      if (k.startsWith("skill:") && v >= 3) active.push(`${k} (${v})`);
    }
    try {
      const indexRaw = readFileSync(path.join(config.memoryDir, "wiki", "index.md"), "utf8");
      const slugs = [...indexRaw.matchAll(/\[\[([^\]]+)\]\]/g)].map(m => m[1]);
      for (const slug of slugs) {
        if (!stats.has(`wiki:${slug}`)) silentWiki.push(slug);
      }
    } catch { /* no wiki index */ }

    let report = "📊 **效用報告（過去 7 天）**\n\n";
    if (active.length > 0) {
      report += `✅ 活躍（≥3 次命中）：\n${active.slice(0, 15).map(a => `  ${a}`).join("\n")}\n\n`;
    }
    const silentTotal = silentFacts.length + silentWiki.length;
    if (silentTotal > 0) {
      report += `💤 沉默（0 次命中）：\n`;
      if (silentFacts.length) report += `  Facts: ${silentFacts.slice(0, 10).join(", ")}${silentFacts.length > 10 ? ` (+${silentFacts.length - 10})` : ""}\n`;
      if (silentWiki.length) report += `  Wiki: ${silentWiki.slice(0, 10).join(", ")}${silentWiki.length > 10 ? ` (+${silentWiki.length - 10})` : ""}\n`;
    }
    if (silentTotal === 0 && active.length === 0) {
      report += "（hit-log 尚無資料，需累積幾天使用後再看）";
    }

    // Tool usage heatmap (from tool_call events in event-log)
    try {
      const tool = getToolUsageStats(7);
      if (tool.total > 0) {
        const top = tool.byTool.slice(0, 10).map(t => {
          const failNote = t.failed > 0 ? ` ⚠️${t.failed} 失敗` : "";
          return `  ${t.name}: ${t.total}${failNote}`;
        });
        const failRate = Math.round((tool.failed / tool.total) * 100);
        report += `\n\n🔧 工具使用（過去 7 天，共 ${tool.total} 次，失敗率 ${failRate}%）：\n${top.join("\n")}`;
        if (tool.byTool.length > 10) report += `\n  …另有 ${tool.byTool.length - 10} 種工具`;
      }
    } catch { /* event-log unavailable — skip tool stats */ }

    // Optional LLM annotation for silent items
    if (silentTotal > 0) {
      try {
        const { detectLlamaCpp, localComplete } = await import("../local-llm.js");
        if (await detectLlamaCpp()) {
          const sample = [...silentFacts.slice(0, 3), ...silentWiki.slice(0, 3)].join(", ");
          const raw = await localComplete(
            `These memory topics/wiki pages had 0 hits in 7 days: ${sample}\n` +
            `For each, give ONE reason (10 words max): "bad description", "topic obsolete", or "just not encountered recently".\n` +
            `Format: name: reason`,
            { maxTokens: 150, timeout: 15000 },
          );
          if (raw) report += `\n🔍 沉默原因（LLM 判斷）：\n${raw}\n`;
        }
      } catch { /* Ollama unavailable — skip annotation */ }
    }

    // Tool usage heatmap (from tool_call events in event-log)
    try {
      const tool = getToolUsageStats(7);
      if (tool.total > 0) {
        const top = tool.byTool.slice(0, 10).map(t => {
          const failNote = t.failed > 0 ? ` (❌${t.failed} fail)` : "";
          return `  ${t.name}: ${t.total}${failNote}`;
        });
        const failRate = Math.round((tool.failed / tool.total) * 100);
        report += `\n\n🔧 **工具使用（7 天 / ${tool.total} 次 / 失敗率 ${failRate}%）**\n${top.join("\n")}`;
        if (tool.byTool.length > 10) report += `\n  …+${tool.byTool.length - 10} 其他工具`;
      }
    } catch { /* event-log unavailable — skip tool stats */ }

    await ctx.reply(report, { parse_mode: "Markdown" });
  } catch (err: any) {
    await ctx.reply(`❌ utility report 失敗：${err.message}`);
  }
}


// ─── /sharedpull ───────────────────────────────────────────────────────────

export async function handleSharedPull(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const sharedDir = path.join(config.memoryDir, "shared");
  try {
    const { execFileSync } = await import("node:child_process");
    const git = (args: string[], timeout = 5000) =>
      execFileSync("git", args, { cwd: sharedDir, encoding: "utf8", timeout }).trim();
    const before = git(["rev-parse", "HEAD"]);
    const out = git(["pull", "--ff-only"], 30000);
    const after = git(["rev-parse", "HEAD"]);

    let newFiles: string[] = [];
    if (before !== after) {
      const diff = git(["diff", "--name-only", before, after]);
      if (diff) {
        newFiles = [...new Set(diff.split(/\r?\n/))]
          .map((f) => f.replace(/\\/g, "/").trim())
          .filter((f) => f.endsWith(".md") && f !== "README.md")
          .sort();
      }
    }

    let msg = `📥 Shared pull：${out || "Already up to date."}`;
    if (newFiles.length > 0) {
      msg += `\n\n📄 新/更新頁面（${newFiles.length}）：\n${newFiles.map((f) => `  - ${f}`).join("\n")}`;
      msg += `\n\n💡 接著會請 agent 讀取上述頁面，判斷是否值得內化為本機 memory/wiki。`;
    }
    await ctx.reply(msg);
    await triggerSharedReview(ctx, sharedDir, newFiles);
  } catch (err: any) {
    await ctx.reply(`⚠️ shared-pull 失敗：${err.message?.slice(0, 200)}`);
  }
}

// ─── /sharedsync ───────────────────────────────────────────────────────────

export async function handleSharedSync(ctx: Context): Promise<import("../dream-config.js").DreamStepResult | void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const sharedDir = path.join(config.memoryDir, "shared");
  const rawArg = typeof ctx.match === "string" ? ctx.match.trim() : "";
  try {
    const result = await syncSharedKnowledge({
      sharedDir,
      message: rawArg || undefined,
    });
    await ctx.reply(formatSharedSyncResult(result));
    await triggerSharedReview(ctx, sharedDir, result.pulledMarkdownFiles);
    return {
      summary: `共享知識同步完成${result.pulledMarkdownFiles.length ? `，收到 ${result.pulledMarkdownFiles.length} 個新頁面` : "，無更新"}`,
      metrics: { newFiles: result.pulledMarkdownFiles.length },
    };
  } catch (err: any) {
    await ctx.reply(`⚠️ shared-sync 失敗：${err.message?.slice(0, 800)}`);
  }
}

