function factsPath(userId: number): string {
  return path.join(config.memoryDir, `facts-${userId}.md`);
}

export async function loadFacts(userId: number): Promise<string> {
  try {
    return (await readFile(factsPath(userId), "utf8")).trim();
  } catch {
    return "";
  }
}

export async function appendFact(userId: number, line: string): Promise<void> {
  await mkdir(config.memoryDir, { recursive: true });
  const text = line.trim();
  const formatted = formatFactLine(text);
  // Guard: if the existing file doesn't end with a newline, prepend one so
  // we never glue two facts together on the same line.
  let prefix = "";
  try {
    const existing = await readFile(factsPath(userId), "utf8");
    if (existing.length > 0 && !existing.endsWith("\n")) prefix = "\n";
  } catch {
    /* file doesn't exist yet — nothing to guard */
  }
  await appendFile(factsPath(userId), prefix + formatted, "utf8");
  // Mirror to per-topic shard. Failures here are warned but not rethrown
  // because the master log is authoritative.
  appendFactShardOnly({
    userId,
    formattedLine: formatted,
    rawText: text,
  });
}

/** Strip leading "- [f_xxxxxx] [timestamp] " or "- [timestamp] " bullet. */
function stripFactPrefix(line: string): string {
  return line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "").trim();
}

/** List existing facts as plain strings (timestamp/bullet stripped). */
export async function listFacts(userId: number): Promise<string[]> {
  const raw = await loadFacts(userId);
  if (!raw) return [];
  return raw
    .split(/\r?\n/)
    .map(stripFactPrefix)
    .filter((s) => s.length > 0);
}

/**
 * Append facts, skipping ones that duplicate existing lines. Comparison is
 * per-line after normalising (strip bullet/timestamp, lowercase, collapse
 * whitespace) — avoids the earlier substring-match footgun where any new
 * fact sharing a phrase with an older one was silently dropped.
 */
export async function appendFactsDedup(userId: number, lines: string[]): Promise<number> {
  const norm = (s: string) => stripFactPrefix(s).toLowerCase().replace(/\s+/g, " ").trim();
  const existing = new Set((await listFacts(userId)).map(norm));
  let added = 0;
  for (const raw of lines) {
    const line = stripFactPrefix(raw);
    if (!line) continue;
    const key = norm(line);
    if (existing.has(key)) continue;
    await appendFact(userId, line);
    existing.add(key);
    added++;
  }
  return added;
}

// Topic classification rules live in ./topic-rules.ts so mcp-memory can
// share the same list and expand topic-name queries into keyword OR match.

interface MemoryBlockOptions {
  tail: number; // 0 = inject everything
  topics: boolean;
  userId?: number; // used to read shard directory for the topic index
  /** Pre-compressed recent facts (from local LLM). If set, replaces raw recent lines. */
  compressed?: string | null;
}

function buildMemoryBlock(facts: string, opts: MemoryBlockOptions): string {
  if (!facts) return "";
  const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
  const total = lines.length;

  // tail=0 → preserve old behaviour (inject everything, no index).
  if (opts.tail === 0 || total <= opts.tail) {
    return (
      "[Long-term memory about this user — use when relevant, don't mention unless asked]\n" +
      lines.join("\n") +
      "\n[End memory]\n\n"
    );
  }

  const recent = lines.slice(-opts.tail);
  const older = lines.slice(0, -opts.tail);

  // Split recent facts into two tracks: user preferences vs agent notes.
  const userPrefLines: string[] = [];
  const agentNoteLines: string[] = [];
  for (const line of recent) {
    const raw = line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "");
    const topic = classifyFact(raw);
    if (topic === "user-preference") {
      userPrefLines.push(line);
    } else {
      agentNoteLines.push(line);
    }
  }

  let recentContent: string;
  if (opts.compressed) {
    // Compressed mode doesn't split (LLM already summarized)
    recentContent = opts.compressed;
  } else if (userPrefLines.length > 0) {
    recentContent =
      "## About this user\n" +
      userPrefLines.join("\n") +
      "\n## Agent notes\n" +
      agentNoteLines.join("\n");
  } else {
    recentContent = recent.join("\n");
  }

  let block =
    `[Long-term memory about this user — recent ${recent.length} of ${total} facts, use when relevant]\n` +
    recentContent +
    "\n[End memory]\n\n";

  if (opts.topics && older.length > 0) {
    // Preferred path: list the user's shard directory and use each
    // file's line count as the topic count. This lets the preamble
    // survive topic rule changes (files reflect what's actually on
    // disk). Falls back to classify-on-the-fly if the shard dir
    // doesn't exist yet (fresh install, pre-rebuild, etc.).
    let indexRows: Array<[string, number]> = [];
    let source: "shard" | "classify" = "classify";
    if (opts.userId !== undefined) {
      const shards = listTopicShards(opts.userId);
      if (shards.length > 0) {
        source = "shard";
        indexRows = shards.map((s) => [s.topic, s.count] as [string, number]);
      }
    }
    if (source === "classify") {
      const counts = new Map<string, number>();
      for (const line of older) {
        const raw = line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "");
        const topic = classifyFact(raw);
        counts.set(topic, (counts.get(topic) ?? 0) + 1);
      }
      indexRows = Array.from(counts.entries()).sort((a, b) => b[1] - a[1]);
    }

    const indexLines = indexRows
      .map(([t, n]) => {
        const hint = topicKeywordHint(t, 3);
        return hint ? `- ${t} (${n}): ${hint}` : `- ${t} (${n})`;
      })
      .join("\n");

    const headerNote =
      source === "shard"
        ? `${older.length} older facts (plus any newer ones), sharded at facts_Topic/${opts.userId}/`
        : `${older.length} older facts grouped by topic`;

    block +=
      `[Memory topics — ${headerNote}]\n` +
      indexLines +
      "\n\n" +
      "If the user asks about a topic above and the recent facts don't cover it,\n" +
      "call the `list_facts` MCP tool with the topic name — the server reads\n" +
      "that shard file directly, e.g. `list_facts({ query: \"bridge-token\" })`.\n" +
      "Use query=\"\" and tail=0 only if you genuinely need the full set.\n" +
      "[End topics]\n\n";
  }

  // 七項行為紀律的壓縮版（原本各自獨立成塊，約 3.4k chars；壓成單塊保留
  // 每條的觸發條件 + 動作，省約一半 preamble 固定成本）。
  block +=
    "[Agent disciplines]\n" +
    "MEMORY — store: preferences, decisions, architecture/env choices, reusable lessons, tool configs, naming rules.\n" +
    "Skip: one-time confirmations, transient status, session-only facts, anything in code/commits or re-derivable in <30s.\n" +
    "Test: useless in a new session 2 weeks later → don't store. Significant decisions keep the WHY:\n" +
    "「因為 X 所以選 Y（排除 Z 因為 W）」/ \"Chose Y because X (rejected Z because W)\".\n" +
    "REFLEXION — same approach fails ≥2 times (tool error, no-match edit, failing build) → STOP, diagnose in 1-2\n" +
    "sentences, switch to a fundamentally different approach (different tool/strategy, or ask user). Never retry a 3rd time.\n" +
    "READ-BACK — after every file write/edit, verify the changed region with read/grep before reporting done.\n" +
    "Never trust the tool's success status alone (strReplace-style silent fails happen).\n" +
    "CONTEXT BUDGET — research-heavy task needing >2 web_fetch or >10 tool calls → delegate to researcher or go concise.\n" +
    "Prefer snippets/summaries over full fetches. On ⚠️ CONTEXT BUDGET WARNING: stop research, produce output now.\n" +
    "Reports: gather conclusions first (≤3 searches), then write the file in ONE call.\n" +
    "ASK BUTTONS — presenting 2+ alternatives, yes/no confirmation, or 「要不要做 X？」→ MUST append <<ASK:...>>.\n" +
    "Self-check triggers: 「哪個」「要選」「方案A/B」「which」「prefer」. Options listed without ASK → add the token before finishing.\n" +
    "MEMORY HONESTY — memory-based answers: say where you found it (topic shard / wiki page); facts >60 days old\n" +
    "→ 「此資訊可能已過時」; absence of records → 「記憶中沒有相關記錄」, never assert non-existence.\n" +
    "Applies only to brain questions (people/decisions/history/preferences), not code or general knowledge.\n" +
    "CAPABILITY GAPS — clumsy pattern recurs ≥2 times → write+test a script in scripts/, then confirm via <<ASK:...>>\n" +
    "before adopting (declined → delete); broader patterns → <<SKILL_PROPOSE:name|reason>>. Check [Available scripts]\n" +
    "first. Never silently add tools; never propose for one-offs.\n" +
    "[End agent disciplines]\n\n";

  return block;
}

