import { mkdir, readFile, appendFile, writeFile } from "node:fs/promises";
import { existsSync, readFileSync, readdirSync } from "node:fs";
import path from "node:path";
import { config, resolveBridgeConfigPath } from "./config.js";
import { classifyFact, topicKeywordHint } from "./topic-rules.js";
import { STICKER_EMOTIONS } from "./stickerMap.js";
import {
  appendFactShardOnly,
  listTopicShards,
  formatFactLine,
} from "./facts-store.js";
import { compressFactsForPreamble } from "./local-llm.js";
import { listPendingIngests } from "./artifact.js";

function factsPath(userId: number): string {
  return path.join(config.memoryDir, `facts-${userId}.md`);
}

export async function loadFacts(userId: number): Promise<string> {
  try {
    return (await readFile(factsPath(userId), "utf8")).trim();
  } catch {
    return "";
  }
}

export async function appendFact(userId: number, line: string): Promise<void> {
  await mkdir(config.memoryDir, { recursive: true });
  const text = line.trim();
  const formatted = formatFactLine(text);
  // Guard: if the existing file doesn't end with a newline, prepend one so
  // we never glue two facts together on the same line.
  let prefix = "";
  try {
    const existing = await readFile(factsPath(userId), "utf8");
    if (existing.length > 0 && !existing.endsWith("\n")) prefix = "\n";
  } catch {
    /* file doesn't exist yet — nothing to guard */
  }
  await appendFile(factsPath(userId), prefix + formatted, "utf8");
  // Mirror to per-topic shard. Failures here are warned but not rethrown
  // because the master log is authoritative.
  appendFactShardOnly({
    userId,
    formattedLine: formatted,
    rawText: text,
  });
}

/** Strip leading "- [f_xxxxxx] [timestamp] " or "- [timestamp] " bullet. */
function stripFactPrefix(line: string): string {
  return line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "").trim();
}

/** List existing facts as plain strings (timestamp/bullet stripped). */
export async function listFacts(userId: number): Promise<string[]> {
  const raw = await loadFacts(userId);
  if (!raw) return [];
  return raw
    .split(/\r?\n/)
    .map(stripFactPrefix)
    .filter((s) => s.length > 0);
}

/**
 * Append facts, skipping ones that duplicate existing lines. Comparison is
 * per-line after normalising (strip bullet/timestamp, lowercase, collapse
 * whitespace) — avoids the earlier substring-match footgun where any new
 * fact sharing a phrase with an older one was silently dropped.
 */
export async function appendFactsDedup(userId: number, lines: string[]): Promise<number> {
  const norm = (s: string) => stripFactPrefix(s).toLowerCase().replace(/\s+/g, " ").trim();
  const existing = new Set((await listFacts(userId)).map(norm));
  let added = 0;
  for (const raw of lines) {
    const line = stripFactPrefix(raw);
    if (!line) continue;
    const key = norm(line);
    if (existing.has(key)) continue;
    await appendFact(userId, line);
    existing.add(key);
    added++;
  }
  return added;
}

// Topic classification rules live in ./topic-rules.ts so mcp-memory can
// share the same list and expand topic-name queries into keyword OR match.

interface MemoryBlockOptions {
  tail: number; // 0 = inject everything
  topics: boolean;
  userId?: number; // used to read shard directory for the topic index
  /** Pre-compressed recent facts (from local LLM). If set, replaces raw recent lines. */
  compressed?: string | null;
}

function buildMemoryBlock(facts: string, opts: MemoryBlockOptions): string {
  if (!facts) return "";
  const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
  const total = lines.length;

  // tail=0 → preserve old behaviour (inject everything, no index).
  if (opts.tail === 0 || total <= opts.tail) {
    return (
      "[Long-term memory about this user — use when relevant, don't mention unless asked]\n" +
      lines.join("\n") +
      "\n[End memory]\n\n"
    );
  }

  const recent = lines.slice(-opts.tail);
  const older = lines.slice(0, -opts.tail);

  // Split recent facts into two tracks: user preferences vs agent notes.
  const userPrefLines: string[] = [];
  const agentNoteLines: string[] = [];
  for (const line of recent) {
    const raw = line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "");
    const topic = classifyFact(raw);
    if (topic === "user-preference") {
      userPrefLines.push(line);
    } else {
      agentNoteLines.push(line);
    }
  }

  let recentContent: string;
  if (opts.compressed) {
    // Compressed mode doesn't split (LLM already summarized)
    recentContent = opts.compressed;
  } else if (userPrefLines.length > 0) {
    recentContent =
      "## About this user\n" +
      userPrefLines.join("\n") +
      "\n## Agent notes\n" +
      agentNoteLines.join("\n");
  } else {
    recentContent = recent.join("\n");
  }

  let block =
    `[Long-term memory about this user — recent ${recent.length} of ${total} facts, use when relevant]\n` +
    recentContent +
    "\n[End memory]\n\n";

  if (opts.topics && older.length > 0) {
    // Preferred path: list the user's shard directory and use each
    // file's line count as the topic count. This lets the preamble
    // survive topic rule changes (files reflect what's actually on
    // disk). Falls back to classify-on-the-fly if the shard dir
    // doesn't exist yet (fresh install, pre-rebuild, etc.).
    let indexRows: Array<[string, number]> = [];
    let source: "shard" | "classify" = "classify";
    if (opts.userId !== undefined) {
      const shards = listTopicShards(opts.userId);
      if (shards.length > 0) {
        source = "shard";
        indexRows = shards.map((s) => [s.topic, s.count] as [string, number]);
      }
    }
    if (source === "classify") {
      const counts = new Map<string, number>();
      for (const line of older) {
        const raw = line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "");
        const topic = classifyFact(raw);
        counts.set(topic, (counts.get(topic) ?? 0) + 1);
      }
      indexRows = Array.from(counts.entries()).sort((a, b) => b[1] - a[1]);
    }

    const indexLines = indexRows
      .map(([t, n]) => {
        const hint = topicKeywordHint(t, 3);
        return hint ? `- ${t} (${n}): ${hint}` : `- ${t} (${n})`;
      })
      .join("\n");

    const headerNote =
      source === "shard"
        ? `${older.length} older facts (plus any newer ones), sharded at facts_Topic/${opts.userId}/`
        : `${older.length} older facts grouped by topic`;

    block +=
      `[Memory topics — ${headerNote}]\n` +
      indexLines +
      "\n\n" +
      "If the user asks about a topic above and the recent facts don't cover it,\n" +
      "call the `list_facts` MCP tool with the topic name — the server reads\n" +
      "that shard file directly, e.g. `list_facts({ query: \"bridge-token\" })`.\n" +
      "Use query=\"\" and tail=0 only if you genuinely need the full set.\n" +
      "[End topics]\n\n";
  }

  // 七項行為紀律的壓縮版（原本各自獨立成塊，約 3.4k chars；壓成單塊保留
  // 每條的觸發條件 + 動作，省約一半 preamble 固定成本）。
  block +=
    "[Agent disciplines]\n" +
    "MEMORY — store: preferences, decisions, architecture/env choices, reusable lessons, tool configs, naming rules.\n" +
    "Skip: one-time confirmations, transient status, session-only facts, anything in code/commits or re-derivable in <30s.\n" +
    "Test: useless in a new session 2 weeks later → don't store. Significant decisions keep the WHY:\n" +
    "「因為 X 所以選 Y（排除 Z 因為 W）」/ \"Chose Y because X (rejected Z because W)\".\n" +
    "REFLEXION — same approach fails ≥2 times (tool error, no-match edit, failing build) → STOP, diagnose in 1-2\n" +
    "sentences, switch to a fundamentally different approach (different tool/strategy, or ask user). Never retry a 3rd time.\n" +
    "READ-BACK — after every file write/edit, verify the changed region with read/grep before reporting done.\n" +
    "Never trust the tool's success status alone (strReplace-style silent fails happen).\n" +
    "CONTEXT BUDGET — research-heavy task needing >2 web_fetch or >10 tool calls → delegate to researcher or go concise.\n" +
    "Prefer snippets/summaries over full fetches. On ⚠️ CONTEXT BUDGET WARNING: stop research, produce output now.\n" +
    "Reports: gather conclusions first (≤3 searches), then write the file in ONE call.\n" +
    "ASK BUTTONS — presenting 2+ alternatives, yes/no confirmation, or 「要不要做 X？」→ MUST append <<ASK:...>>.\n" +
    "Self-check triggers: 「哪個」「要選」「方案A/B」「which」「prefer」. Options listed without ASK → add the token before finishing.\n" +
    "MEMORY HONESTY — memory-based answers: say where you found it (topic shard / wiki page); facts >60 days old\n" +
    "→ 「此資訊可能已過時」; absence of records → 「記憶中沒有相關記錄」, never assert non-existence.\n" +
    "Applies only to brain questions (people/decisions/history/preferences), not code or general knowledge.\n" +
    "CAPABILITY GAPS — clumsy pattern recurs ≥2 times → write+test a script in scripts/, then confirm via <<ASK:...>>\n" +
    "before adopting (declined → delete); broader patterns → <<SKILL_PROPOSE:name|reason>>. Check [Available scripts]\n" +
    "first. Never silently add tools; never propose for one-offs.\n" +
    "[End agent disciplines]\n\n";

  return block;
}

/**
 * Char-length breakdown of the preamble by section. Useful for the
 * bridge's context-usage UI so the user can see where the tokens go
 * (tool notes / env / memory) without having to inspect the raw string.
 *
 * All counts are raw character lengths; convert to tokens via the same
 * ~chars/4 heuristic used elsewhere (`estimateTokens`).
 */
export interface PreambleBreakdown {
  /** Full preamble text (same as the string returned by buildPreamble). */
  text: string;
  /** Total chars (= text.length). Convenience so callers don't re-measure. */
  total: number;
  /** sendFileNote + askNote + scheduleNote combined. */
  toolNotes: number;
  /** Environment block (MEMORY_DIR / SKILL_DIR / AGENT_CONFIG_DIR / USER_ID). */
  envBlock: number;
  /** Long-term memory block (recent facts + topic index). 0 if no facts. */
  memoryBlock: number;
  /** Daily log block (most recent dailylog). 0 if none. */
  dailylogBlock: number;
  /** Wiki index block (page titles from wiki/index.md). 0 if no wiki. */
  wikiBlock: number;
  /** Document tree indexes listing. 0 if no indexes. */
  indexBlock: number;
  /** Available agent-developed scripts (tool-* in scripts/). 0 if none. */
  scriptsBlock: number;
  /** User profile block (structured user identity/preferences). 0 if none. */
  userProfileBlock: number;
  /** Stripped tail facts included in preamble — for dedup in memory-recall. */
  tailFacts: Set<string>;
}



/**
 * Like buildPreamble but also returns per-section char lengths so the
 * bridge can display where context tokens are going. Prefer this in
 * new code; buildPreamble is kept for callers that only want the text.
 */
export function buildPreambleWithBreakdown(
  facts: string,
  userId?: number,
  opts?: { tailOverride?: number; compressed?: string | null; agentCommand?: string }
): PreambleBreakdown {
  const {
    sendFileNote,
    askNote,
    scheduleNote,
    skillUsedNote,
    goalDoneNote,
    restartNote,
    stickerNote,
    wikiQueryNote,
    skillProposeNote,
    continueNote,
    relayDelegateNote,
    specialistProxyNote,
    parallelDelegateNote,
    rtkNote,
    envBlock,
    memoryBlock,
    dailylogBlock,
    wikiBlock,
    indexBlock,
    scriptsBlock,
    userProfileBlock,
  } = buildPreambleSections(facts, userId, opts?.tailOverride, opts?.compressed, opts?.agentCommand);
  const text =
    sendFileNote +
    askNote +
    scheduleNote +
    skillUsedNote +
    goalDoneNote +
    restartNote +
    stickerNote +
    wikiQueryNote +
    skillProposeNote +
    continueNote +
    relayDelegateNote +
    specialistProxyNote +
    parallelDelegateNote +
    rtkNote +
    envBlock +
    userProfileBlock +
    memoryBlock +
    dailylogBlock +
    wikiBlock +
    indexBlock +
    scriptsBlock;
  // Build a Set of stripped tail facts for dedup in memory-recall.
  const tailCount = opts?.tailOverride ?? config.memoryPreambleTail;
  const tailFacts = new Set<string>();
  if (facts) {
    const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
    const recent = lines.slice(-tailCount);
    for (const line of recent) {
      tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
    }
  }

  return {
    text,
    total: text.length,
    toolNotes:
      sendFileNote.length +
      askNote.length +
      scheduleNote.length +
      skillUsedNote.length +
      goalDoneNote.length +
      restartNote.length +
      stickerNote.length +
      wikiQueryNote.length +
      skillProposeNote.length +
      continueNote.length +
      relayDelegateNote.length +
      specialistProxyNote.length,
    envBlock: envBlock.length,
    memoryBlock: memoryBlock.length,
    dailylogBlock: dailylogBlock.length,
    wikiBlock: wikiBlock.length,
    indexBlock: indexBlock.length,
    scriptsBlock: scriptsBlock.length,
    userProfileBlock: userProfileBlock.length,
    tailFacts,
  };
}

export function buildPreamble(facts: string, userId?: number): string {
  return buildPreambleWithBreakdown(facts, userId).text;
}

/**
 * Minimal preamble for local models (Ollama). Keeps total under ~2000 tokens
 * so small models don't choke on an oversized system prompt.
 * Includes: identity, recent facts, memory tool hints.
 */
export function buildLocalPreamble(facts: string, userId?: number): PreambleBreakdown {
  const lines = facts ? facts.split(/\r?\n/).filter((l) => l.trim().length > 0) : [];
  const tail = Math.min(5, lines.length);
  const recent = lines.slice(-tail);
  const recentContent = recent.map((l) => l.trim()).join("\n");

  const toolGuide =
    "[MCP Tools — call these via tool_call]\n" +
    "• remember({ text }) — store a fact to long-term memory. Use for user preferences, decisions, lessons.\n" +
    "• list_facts({ query, tail? }) — retrieve facts. query=topic name or substring. tail caps results (default 20).\n" +
    "• forget({ query, confirm? }) — delete facts by substring match. First call previews; second call with confirm token deletes.\n" +
    "Rules: one fact per remember call; short self-contained sentences; skip trivial/transient info.\n" +
    "[End tools]\n\n";

  let text =
    "You are a helpful AI assistant. Respond in the user's language. Be concise.\n" +
    toolGuide;

  if (recentContent) {
    text += `[Recent memory — ${tail} of ${lines.length} facts]\n${recentContent}\n[End memory]\n\n`;
  }

  const tailFacts = new Set<string>();
  for (const line of recent) {
    tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
  }

  return {
    text,
    total: text.length,
    toolNotes: toolGuide.length,
    envBlock: 0,
    memoryBlock: recentContent.length,
    dailylogBlock: 0,
    wikiBlock: 0,
    indexBlock: 0,
    scriptsBlock: 0,
    userProfileBlock: 0,
    tailFacts,
  };
}

/**
 * Internal: builds each section of the preamble separately so
 * buildPreambleWithBreakdown can measure them. Ordering matches what
 * buildPreamble concatenates.
 */
function buildPreambleSections(
  facts: string,
  userId?: number,
  tailOverride?: number,
  compressed?: string | null,
  agentCommand?: string,
): {
  sendFileNote: string;
  askNote: string;
  scheduleNote: string;
  skillUsedNote: string;
  goalDoneNote: string;
  restartNote: string;
  stickerNote: string;
  wikiQueryNote: string;
  skillProposeNote: string;
  continueNote: string;
  relayDelegateNote: string;
  specialistProxyNote: string;
  parallelDelegateNote: string;
  rtkNote: string;
  envBlock: string;
  memoryBlock: string;
  dailylogBlock: string;
  wikiBlock: string;
  indexBlock: string;
  scriptsBlock: string;
  userProfileBlock: string;
} {
  const sendFileNote =
    "[Telegram bridge tool: send file]\n" +
    "`<<SEND_FILE:絕對路徑>>` — 附檔給使用者（圖片≤10MB走photo，餘走document）。路徑須在 TG_SEND_ROOTS 底下。\n" +
    "僅在使用者明確要求傳檔時加；產生/儲存檔案不構成傳檔意圖，回報路徑即可。\n" +
    "[End tool]\n\n";
  const askNote =
    "[Telegram bridge tool: ask with buttons]\n" +
    "`<<ASK:id|key=label|*key=label|...>>`（單行）— 渲染 inline keyboard，點擊回送 `[ASK:id] key`。\n" +
    "限制：id≤32 key≤20 [a-zA-Z0-9_-]；label≤40 不含`|``=`；1-8選項；`*`標推薦（至多一個）。\n" +
    "選項說明長時正文列 1./2./3.，label 只放短標題。違反限制會原封顯示無法渲染。\n" +
    "[End tool]\n\n";
  const scheduleNote =
    "[Telegram bridge tool: schedule]\n" +
    "`<<SCHEDULE:<time>|<prompt>>>`（單行）— 建立延遲/常態性排程。\n" +
    "一次性：`30s`/`15m`/`2h`/`1d`/`HH:MM`/`tomorrow HH:MM`/`MM-DD HH:MM`/`YYYY-MM-DD HH:MM`。\n" +
    "常態性：`every 30m`/`daily 09:00`/`weekly mon 09:00`/`cron */5 * * * *`。\n" +
    "prompt≤1000字，不可含`>>`。單則至多3個。僅在使用者明確要求排程時使用。\n" +
    "[End tool]\n\n";
  const skillUsedNote =
    "[Telegram bridge tool: report skill use]\n" +
    "`<<SKILL_USED:skill-name|reason>>`（單行）— 你參考了某 SKILL.md 時加。\n" +
    "name=資料夾名 kebab-case≤60；reason≤500 不含`|`或換行。一則至多5個，重複去重。\n" +
    "[End tool]\n\n";
  const goalDoneNote =
    "[Telegram bridge tool: goal done signal]\n" +
    "`<<GOAL_DONE:reason>>`（單行）— /goal 標的達成時加在回覆最後。\n" +
    "reason≤500 不含`|`或換行。未完成不加。/goal 未啟動時忽略。\n" +
    "[End tool]\n\n";
  const restartNote =
    "[Telegram bridge tool: restart]\n" +
    "`<<RESTART:reason>>`（單行）— 重啟 session（context 過大、工具異常、需刷新 preamble）。\n" +
    "重要：restart 前先 remember() 存工作狀態，格式：\n" +
    "  - `[WS] task: <目標>` — 當前高層任務\n" +
    "  - `[WS] completed: <已完成項>` — 本 session 完成的事（可多條）\n" +
    "  - `[WS] blocked: <阻塞項>` — 等待中的事\n" +
    "  - `[WS] key_refs: <重要路徑或值>` — 需帶到下個 session 的參考\n" +
