/**
 * Environment preamble: tells the agent where this bridge stores memory,
 * skills, agent config files, and which Telegram user owns the session.
 * Skills and long-term notes can reference these as ${MEMORY_DIR},
 * ${SKILL_DIR}, ${AGENT_CONFIG_DIR}, ${USER_ID} rather than hard-coding
 * machine-specific paths — so the same SKILL.md works on the Kiro box,
 * the Codex box, and the Claude box.
 *
 * Heuristic: agent.command name hints which CLI we're paired with
 * (kiro → ~/.kiro, codex → ~/.codex, claude → ~/.claude). Any of the
 * three variables can be overridden via the matching env var.
 */
/**
 * Build relay delegate tool note from external config file.
 * Reads MEMORY_DIR/config/relay-peers.json (fallback: AGENT_CONFIG_DIR).
 */
function buildRelayDelegateNote(): string {
  interface PeerConfig {
    abilities: string[];
    delegateWhen: string[];
  }
  const cfgPath = resolveBridgeConfigPath("relay-peers.json", detectAgentConfigDir());
  let peers: Record<string, PeerConfig>;
  try {
    peers = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    console.warn(`[preamble] relay-peers.json not found at ${cfgPath} — relay delegate tool note disabled`);
    return "";
  }
  const names = Object.keys(peers);
  if (names.length === 0) return "";
  let note = "[Telegram bridge tool: relay delegate]\n";
  note += "`<<RELAY_DELEGATE:<peer>|goal prompt>>`（單行）— 委派任務給另一台機器上的 AI agent。\n";
  note += "也接受 JSON 格式：`<<RELAY_DELEGATE:<peer>|{\"id\":\"<id>\",\"goal\":\"...\",\"context\":\"...\"}>>`\n";
  note += "純文字時 bridge 自動產生 id。goal prompt 不可含 `>>` 或 `|`。\n";
  note += "Bridge 會自動保存你的工作狀態，對方完成後結果靜默注入你的 session。\n\n";
  for (const [name, cfg] of Object.entries(peers)) {
    const extra = (cfg as any).note ? `（${(cfg as any).note}）` : "";
    note += `「${name}」${extra}的能力：\n`;
    for (const a of cfg.abilities) note += `- ${a}\n`;
    note += `\n何時委派給「${name}」：\n`;
    for (const w of cfg.delegateWhen) note += `- ${w}\n`;
    note += "\n";
  }
  note += "格式規則：\n";
  note += "- 純文字格式（推薦）：`<<RELAY_DELEGATE:peer|任務描述>>`\n";
  note += "- JSON 格式（需要帶 context/maxTurns 時）：`<<RELAY_DELEGATE:peer|{\"id\":\"rd_xxx\",\"goal\":\"...\",\"context\":\"...\"}>>` \n";
  note += "- goal/prompt 不可含 `>>` 或 `|`\n";
  note += "- goal 應含三要素：目標與動機 / 驗收條件 / 回報格式（只回結論+檔案:行號，長產物存檔回傳路徑）\n";
  note += "- 不要等結果——發出後正常回覆使用者「已委派」即可\n";
  note += "- ⚠️ 重要：發 RELAY_DELEGATE 的 turn 必須包含至少一個 tool call（如 list_facts），否則 token 會被 CLI 吞掉不送出\n";
  note += "[End tool]\n\n";
  return note;
}

function buildSpecialistProxyNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string; cwd: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    return "";
  }
  if (!Array.isArray(specs) || specs.length === 0) return "";
  let note = "[Telegram bridge tool: specialist proxy]\n";
  note += "`<<SPECIALIST_PROXY:name|使用者的原始訊息>>`（單行）— 把使用者的訊息轉交給本機 specialist 即時回答。\n";
  note += "進入 proxy 模式後，使用者後續訊息直送 specialist，回覆直送使用者，直到使用者說 /back。\n";
  note += "Specialist 的記憶會回流到你的 facts。proxy 結束時你會收到對話摘要。\n\n";
  note += "可用 specialist：\n";
  for (const s of specs) {
    note += `- ${s.name}（工作目錄：${s.cwd}）\n`;
  }
  note += "\n使用時機：使用者的問題明確屬於某 specialist 的領域，且需要即時互動（不是背景任務）。\n";
  note += "背景任務用 RELAY_DELEGATE；即時對話用 SPECIALIST_PROXY。\n";
  note += "[End tool]\n\n";
  return note;
}

function buildParallelDelegateNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    return "";
  }
  if (!Array.isArray(specs) || specs.length === 0) return "";
  let note = "[Telegram bridge tool: parallel delegate]\n";
  note += "`<<PARALLEL_DELEGATE:task_id|specialist_name|goal prompt>>`（單行）— 並行委派多個任務給 specialist。\n";
  note += "同一個 turn 放多個 PARALLEL_DELEGATE，bridge 會同時 spawn 多個獨立 instance 並行執行。\n";
  note += "全部完成後結果一次注入你的 session（格式：[PARALLEL_RESULT:task_id]）。\n\n";
  note += "格式規則：\n";
  note += "- task_id：唯一識別碼（如 `pt_1`、`pt_2`）\n";
  note += "- specialist_name：目標 specialist（同一個 name 可以開多個 instance）\n";
  note += "- goal prompt：任務描述（不可含 `>>` 或 `|`），同樣應含三要素：目標與動機 / 驗收條件 / 回報格式\n";
  note += "- 每個 task 獨立 instance，互不干擾——但要避免多個 task 改同一個檔案\n";
  note += "- ⚠️ 同樣需要至少一個 tool call 防止 CLI 吞 token\n\n";
  note += "使用時機：任務可拆成多個獨立子任務且各自耗時 > 1 分鐘（如同時研究多支影片、同時改不同模組）。\n";
  note += "單一任務用 RELAY_DELEGATE；可並行的多任務用 PARALLEL_DELEGATE。\n";
  note += "[End tool]\n\n";
  return note;
}

